package pe.edu.utp.tmo.controller; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.dto.request.UserCreateRequest; import pe.edu.utp.tmo.dto.response.UserResponse; import pe.edu.utp.tmo.service.UserService; @RestController @RequestMapping("/api/admin/users") public class UserController{ private final UserService s; public UserController(UserService s){this.s=s;} @PostMapping ResponseEntity<UserResponse> crear(@Valid @RequestBody UserCreateRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(s.crear(r));}}